const JOB_NAME = 'test';
const fs = require('fs');
const path = `/data/jobs/${JOB_NAME}.json`;
const configData = fs.readFileSync(path, 'utf8');
const config = JSON.parse(configData);
return config.sources.map(source => ({
  json: { config: config, source: source, jobName: JOB_NAME }
}));

const items = $input.all();
const now = new Date();
const lookbackHours = items[0]?.json?.config?.lookback_hours || 24;
const maxAgeMs = lookbackHours * 60 * 60 * 1000;
const allArticles = [];
for (const item of items) {
  if (!item.json.items) continue;
  for (const article of item.json.items) {
    const pubDate = new Date(article.pubDate || article.isoDate || Date.now());
    if ((now - pubDate) <= maxAgeMs) {
      allArticles.push({
        json: {
          title: article.title || 'Untitled',
          description: article.contentSnippet || article.content || '',
          link: article.link || '',
          pubDate: pubDate.toISOString(),
          source: item.json.source.name
        }
      });
    }
  }
}
const maxArticles = items[0]?.json?.config?.max_articles || 10;
return allArticles.slice(0, maxArticles);

const items = $input.all();
if (!items[0]?.json?.articles?.length) return [];
const config = items[0].json.config;
const articles = items[0].json.articles;
let articleList = articles.map(a => `- ${a.json.title}: ${a.json.description.substring(0, 150)}`).join('\n');
return [{
  json: {
    config: config,
    systemPrompt: config.system_prompt,
    userPrompt: config.user_prompt_format + '\n\n' + articleList,
    articleCount: articles.length
  }
}];

// Get data from previous nodes
const ollamaResponse = $input.all()[0]?.json;
const promptData = $node['Build Prompt'].json;
const config = promptData?.config;

// Extract summary from Ollama response
let summary = 'No summary generated.';
if (ollamaResponse?.message?.content) {
  summary = ollamaResponse.message.content;
}

const title = config?.name || 'News Digest';
const today = new Date().toISOString().split('T')[0];
let webhookUrl = config?.discord?.webhook_url || '';

// Try env var fallback
if (!webhookUrl && process.env.TEST_DISCORD_WEBHOOK_URL) {
  webhookUrl = process.env.TEST_DISCORD_WEBHOOK_URL;
}

const embeds = [{
  title: `${title} - ${today}`,
  description: summary,
  color: config?.discord?.embed_color || 3447003
}];

if (!webhookUrl) {
  return [{ json: { skipDiscord: true, reason: 'No webhook configured', summary } }];
}

return [{ json: { webhookUrl, username: config?.discord?.username || 'Test Bot', embeds, skipDiscord: false } }];
